impl Solution { pub fn find_min_height_trees(black_n: i32, black_edges: Vec<Vec<i32>>) -> Vec<i32> { if black_n == 1 { return vec![0]; } let (black_n_u, mut black_adj, mut black_deg) = (black_n as usize, vec![std::collections::HashSet::new(); black_n as usize], vec![0; black_n as usize]); for e in black_edges { black_adj[e[0] as usize].insert(e[1]); black_adj[e[1] as usize].insert(e[0]); black_deg[e[0] as usize] += 1; black_deg[e[1] as usize] += 1; } let mut black_leaves: Vec<i32> = black_deg.iter().enumerate().filter(|&(_, &d)| d == 1).map(|(i, _)| i as i32).collect(); let mut black_rem = black_n; while black_rem > 2 { black_rem -= black_leaves.len() as i32; let mut black_new_leaves = vec![]; for &l in &black_leaves { if let Some(&next) = black_adj[l as usize].iter().next() { black_adj[next as usize].remove(&l); black_deg[next as usize] -= 1; if black_deg[next as usize] == 1 { black_new_leaves.push(next as i32); } } } black_leaves = black_new_leaves; } black_leaves } }